class SourceControlSystem:
    def __init__(self):
        self.files = {}

    def check_out(self, file_name):
        if file_name not in self.files:
            self.files[file_name] = open(file_name, 'w+')
        else:
            print(f"{file_name} is already checked out.")

    def check_in(self, file_name):
        if file_name in self.files:
            self.files[file_name].close()
            del self.files[file_name]
        else:
            print(f"{file_name} is not checked out.")

    def write(self, file_name, content):
        self.files[file_name].write(content)
        self.files[file_name].flush()

    def read(self, file_name):
        return self.files[file_name].read()
